 1→import { useEffect, useState } from 'react';
 2→import { Stack, useRouter, useSegments } from 'expo-router';
 3→import { supabase } from '../lib/supabase';
 4→import { useAuthStore } from '../lib/store';
 5→import { useNotifications } from '../hooks/useNotifications';
 6→
 7→export default function RootLayout() {
 8→  const { session, setSession } = useAuthStore();
 9→  const segments = useSegments();
10→  const router = useRouter();
11→  const [ready, setReady] = useState(false);
12→
13→  useNotifications();
14→
15→  useEffect(() => {
16→    supabase.auth.getSession().then(({ data: { session } }) => {
17→      setSession(session);
18→      setReady(true);
19→    });
20→    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
21→      setSession(session);
22→    });
23→    return () => subscription.unsubscribe();
24→  }, []);
25→
26→  useEffect(() => {
27→    if (!ready) return;
28→    const inAuth = segments[0] === '(auth)';
29→    if (!session && !inAuth) {
30→      router.replace('/(auth)/login');
31→    } else if (session && inAuth) {
32→      router.replace('/(tabs)');
33→    }
34→  }, [session, segments, ready]);
35→
36→  return <Stack screenOptions={{ headerShown: false }} />;
37→}
