  4→import { useAuthStore } from '../../lib/store';
  5→
  6→interface RewardItem {
  7→  id: string;
  8→  name: string;
  9→  description: string | null;
 10→  discount_type: string;
 11→  discount_value: number;
 12→  points_cost: number | null;
 13→  stamps_required: number | null;
 14→  program_name: string;
 15→  program_type: string;
 16→  card_id: string;
 17→  can_redeem: boolean;
 18→}
 19→
 20→export default function RewardsScreen() {
 21→  const [rewards, setRewards] = useState<RewardItem[]>([]);
 22→  const [loading, setLoading] = useState(true);
 23→  const session = useAuthStore((s) => s.session);
 24→
 25→  async function fetchRewards() {
 26→    if (!session) return;
 27→    const { data: cards } = await supabase
 28→      .from('customer_cards')
 29→      .select('*, loyalty_programs(name, type, rewards(*))')
 30→      .eq('customer_id', session.user.id);
 31→
 32→    const items: RewardItem[] = [];
 33→    cards?.forEach((card: any) => {
 34→      const program = card.loyalty_programs;
 35→      program.rewards?.forEach((r: any) => {
 36→        const canRedeem = program.type === 'stamp'
 37→          ? card.current_stamps >= (r.stamps_required || 0)
 38→          : card.current_points >= (r.points_cost || 0);
 39→        items.push({
 40→          ...r,
 41→          program_name: program.name,
 42→          program_type: program.type,
 43→          card_id: card.id,
 44→          can_redeem: canRedeem,
 45→        });
 46→      });
 47→    });
 48→    setRewards(items);
 49→    setLoading(false);
 50→  }
 51→
 52→  useEffect(() => { fetchRewards(); }, [session]);
 53→
 54→  async function handleRedeem(item: RewardItem) {
 55→    Alert.alert('Redeem Reward', `Use ${item.program_type === 'stamp' ? item.stamps_required + ' stamps' : item.points_cost + ' points'} for "${item.name}"?`, [
 56→      { text: 'Cancel' },
 57→      {
 58→        text: 'Redeem', onPress: async () => {
 59→          const { data, error } = await supabase.functions.invoke('redeem-reward', {
 60→            body: { card_id: item.card_id, reward_id: item.id },
 61→          });
 62→          if (error) { Alert.alert('Error', error.message); return; }
 63→          Alert.alert('Redeemed!', `You got: ${data.reward_name}`);
 64→          fetchRewards();
 65→        },
 66→      },
 67→    ]);
 68→  }
 69→
 70→  return (
 71→    <View style={styles.container}>
 72→      <Text style={styles.title}>Rewards</Text>
 73→      <FlatList
 74→        data={rewards}
 75→        keyExtractor={(item) => item.id}
 76→        renderItem={({ item }) => (
 77→          <View style={styles.card}>
 78→            <Text style={styles.program}>{item.program_name}</Text>
 79→            <Text style={styles.name}>{item.name}</Text>
 80→            {item.description && <Text style={styles.desc}>{item.description}</Text>}
 81→            <Text style={styles.cost}>
 82→              {item.program_type === 'stamp' ? `${item.stamps_required} stamps` : `${item.points_cost} pts`}
 83→              {' \u00b7 '}
 84→              {item.discount_type === 'freebie' ? 'Free' : `${item.discount_value}${item.discount_type === 'percentage' ? '%' : '\u20ac'} off`}
 85→            </Text>
 86→            <TouchableOpacity
 87→              style={[styles.button, !item.can_redeem && styles.buttonDisabled]}
 88→              onPress={() => handleRedeem(item)}
 89→              disabled={!item.can_redeem}
 90→            >
 91→              <Text style={styles.buttonText}>{item.can_redeem ? 'Redeem' : 'Not enough'}</Text>
 92→            </TouchableOpacity>
 93→          </View>
 94→        )}
 95→        ListEmptyComponent={<Text style={styles.empty}>{loading ? 'Loading...' : 'No rewards available yet.'}</Text>}
 96→        refreshControl={<RefreshControl refreshing={loading} onRefresh={fetchRewards} />}
 97→        contentContainerStyle={styles.list}
 98→      />
 99→    </View>
100→  );
101→}
