 1→import { useState } from 'react';
 2→import { View, Text, StyleSheet, TouchableOpacity, Alert } from 'react-native';
 3→import { CameraView, useCameraPermissions } from 'expo-camera';
 4→import { supabase } from '../../lib/supabase';
 5→
 6→export default function ScanScreen() {
 7→  const [permission, requestPermission] = useCameraPermissions();
 8→  const [scanned, setScanned] = useState(false);
 9→  const [processing, setProcessing] = useState(false);
10→
11→  if (!permission) return <View />;
12→  if (!permission.granted) {
13→    return (
14→      <View style={styles.center}>
15→        <Text style={styles.text}>Camera permission is required to scan QR codes</Text>
16→        <TouchableOpacity style={styles.button} onPress={requestPermission}>
17→          <Text style={styles.buttonText}>Grant Permission</Text>
18→        </TouchableOpacity>
19→      </View>
20→    );
21→  }
22→
23→  async function handleBarCodeScanned({ data }: { data: string }) {
24→    if (scanned || processing) return;
25→    setScanned(true);
26→    setProcessing(true);
27→
28→    try {
29→      const payload = JSON.parse(data);
30→      if (payload.type !== 'loyalty_scan') {
31→        Alert.alert('Invalid QR', 'This is not a loyalty QR code.');
32→        return;
33→      }
34→
35→      const { data: result, error } = await supabase.functions.invoke('validate-scan', {
36→        body: { qr_id: payload.qr_id, secret: payload.secret },
37→      });
38→
39→      if (error) throw error;
40→
41→      if (result.success) {
42→        const msg = result.type === 'stamp'
43→          ? `Stamp added! ${result.new_total}/${result.goal}`
44→          : `+${result.added} points! Total: ${result.new_total}`;
45→        Alert.alert(result.program_name, msg);
46→      } else {
47→        Alert.alert('Error', result.error || 'Scan failed');
48→      }
49→    } catch (e: any) {
50→      Alert.alert('Error', e.message || 'Could not process QR code');
51→    } finally {
52→      setProcessing(false);
53→      setTimeout(() => setScanned(false), 2000);
54→    }
55→  }
56→
57→  return (
58→    <View style={styles.container}>
59→      <CameraView
60→        style={styles.camera}
61→        barcodeScannerSettings={{ barcodeTypes: ['qr'] }}
62→        onBarcodeScanned={scanned ? undefined : handleBarCodeScanned}
63→      >
64→        <View style={styles.overlay}>
65→          <View style={styles.frame} />
66→          <Text style={styles.hint}>{processing ? 'Processing...' : 'Point at a loyalty QR code'}</Text>
67→        </View>
68→      </CameraView>
69→    </View>
70→  );
71→}
72→
73→const styles = StyleSheet.create({
74→  container: { flex: 1 },
75→  center: { flex: 1, justifyContent: 'center', alignItems: 'center', padding: 24 },
76→  text: { fontSize: 16, textAlign: 'center', marginBottom: 16 },
77→  camera: { flex: 1 },
78→  overlay: { flex: 1, justifyContent: 'center', alignItems: 'center' },
79→  frame: { width: 250, height: 250, borderWidth: 3, borderColor: '#fff', borderRadius: 20 },
80→  hint: { color: '#fff', fontSize: 16, marginTop: 20, fontWeight: '600' },
81→  button: { backgroundColor: '#6366f1', padding: 16, borderRadius: 12 },
82→  buttonText: { color: '#fff', fontSize: 16, fontWeight: '600' },
83→});
