import { useState } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, Alert } from 'react-native';
import { CameraView, useCameraPermissions } from 'expo-camera';
import { useTranslation } from 'react-i18next';
import { supabase } from '../../lib/supabase';

export default function ScanScreen() {
  const [permission, requestPermission] = useCameraPermissions();
  const [scanned, setScanned] = useState(false);
  const [processing, setProcessing] = useState(false);
  const { t } = useTranslation();

  if (!permission) return <View />;
  if (!permission.granted) {
    return (
      <View style={styles.center}>
        <Text style={styles.text}>Camera permission is required to scan QR codes</Text>
        <TouchableOpacity style={styles.button} onPress={requestPermission}>
          <Text style={styles.buttonText}>Grant Permission</Text>
        </TouchableOpacity>
      </View>
    );
  }

  async function handleBarCodeScanned({ data }: { data: string }) {
    if (scanned || processing) return;
    setScanned(true);
    setProcessing(true);

    try {
      const payload = JSON.parse(data);
      if (payload.type !== 'loyalty_scan') {
        Alert.alert(t('scan.error'), 'This is not a loyalty QR code.');
        return;
      }

      const { data: result, error } = await supabase.functions.invoke('validate-scan', {
        body: { qr_id: payload.qr_id, secret: payload.secret },
      });

      if (error) throw error;

      if (result.success) {
        const msg = result.type === 'stamp'
          ? `Stamp added! ${result.new_total}/${result.goal}`
          : `+${result.added} points! Total: ${result.new_total}`;
        Alert.alert(t('scan.success'), msg);
      } else {
        Alert.alert(t('common.error'), result.error || t('scan.error'));
      }
    } catch (e: any) {
      Alert.alert(t('common.error'), e.message || t('scan.error'));
    } finally {
      setProcessing(false);
      setTimeout(() => setScanned(false), 2000);
    }
  }

  return (
    <View style={styles.container}>
      <CameraView
        style={styles.camera}
        barcodeScannerSettings={{ barcodeTypes: ['qr'] }}
        onBarcodeScanned={scanned ? undefined : handleBarCodeScanned}
      >
        <View style={styles.overlay}>
          <View style={styles.frame} />
          <Text style={styles.hint}>{processing ? t('common.loading') : t('scan.scanning')}</Text>
        </View>
      </CameraView>
    </View>
  );
}

